const results = $.steps.webSearch.response.results || [];
let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});
return { sourcesText, sourceCount: results.length, topSources: results.slice(0, 3).map(r => ({ title: r.title || 'Untitled', url: r.url || '' })) };

const d = $.steps.compileSources.output;
const question = $.input.question;

let prompt = 'You are a helpful AI assistant for a Discord server. Answer the following question using web search results.\n\n';
prompt += 'QUESTION: ' + question + '\n\n';
prompt += 'WEB SEARCH RESULTS (' + d.sourceCount + ' sources):\n';
prompt += d.sourcesText + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Provide a clear, comprehensive answer\n';
prompt += '- Cite sources by number [1], [2], etc.\n';
prompt += '- Keep the answer concise but informative (under 1800 characters for Discord)\n';
prompt += '- Use Discord markdown formatting: **bold**, *italic*, > for quotes, `code`\n';
prompt += '- Do NOT use Slack-style formatting\n';
prompt += '- Be conversational and friendly\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "the answer in Discord markdown format",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "sourcesUsed": [1, 2],\n';
prompt += '  "followUpSuggestions": ["suggestion 1", "suggestion 2"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', sourcesUsed: [], followUpSuggestions: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const topSources = $.steps.compileSources.output.topSources || [];
const sourceCount = $.steps.compileSources.output.sourceCount;

const confEmoji = ai.confidence === 'high' ? ':green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':yellow_circle:';

let message = '**Question:** ' + question + '\n\n';
message += (ai.answer || 'No answer generated.').slice(0, 1600) + '\n\n';

if (topSources.length > 0) {
  message += '**Sources:**\n';
  topSources.forEach((s, i) => {
    message += (i + 1) + '. [' + s.title + '](' + s.url + ')\n';
  });
  message += '\n';
}

message += confEmoji + ' Confidence: **' + (ai.confidence || 'medium') + '** | Sources: **' + sourceCount + '**';

if (ai.followUpSuggestions && ai.followUpSuggestions.length > 0) {
  message += '\n\n*Try asking:* ' + ai.followUpSuggestions.slice(0, 2).join(' | ');
}

return { content: message.slice(0, 2000) };
